/**
 * After `vite build`, copy stocks.index.json next to static-user/index.html when present.
 * Source is generated by scripts/generate_stock_index.py → apps/dsa-web/public/.
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkgRoot = path.resolve(__dirname, '..');
const src = path.resolve(pkgRoot, '../dsa-web/public/stocks.index.json');
const dest = path.resolve(pkgRoot, '../../static-user/stocks.index.json');

try {
  if (fs.existsSync(src)) {
    fs.mkdirSync(path.dirname(dest), { recursive: true });
    fs.copyFileSync(src, dest);
    console.log('[copy-stock-index] copied to static-user/');
  } else {
    console.warn('[copy-stock-index] skip: source missing (run scripts/generate_stock_index.py)');
  }
} catch (e) {
  console.warn('[copy-stock-index] skip:', e instanceof Error ? e.message : e);
}
